+static gboolean
+gst_hash_g_date_time (const GDateTime * dt, guint * res)
+{
+  gint64 unix_time;
+
+  unix_time = g_date_time_to_unix ((GDateTime *) dt);
+  *res = g_int64_hash ((gconstpointer) & unix_time);
+  return TRUE;
+}
